
(function() {
    class EmbeddedProject extends HTMLElement {
        constructor() {
            super();
            this.attachShadow({mode: 'open'});
        }

        connectedCallback() {
            const shadow = this.shadowRoot;
            const decodeB64 = (str) => {
                try {
                    const binary = atob(str);
                    try {
                        return decodeURIComponent(escape(binary));
                    } catch (e) {
                        return binary;
                    }
                } catch (e) {
                    console.error("Embedded Project: Base64 decode failed", e);
                    return "";
                }
            };

            // 1. Inject External CSS
            [].forEach(href => {
                const link = document.createElement('link');
                link.rel = 'stylesheet';
                link.href = href;
                shadow.appendChild(link);
            });

            // 2. Inject Internal Styles
            const style = document.createElement('style');
            style.textContent = `:host { display: block; width: 100%; min-height: 100px; } .shadow-body { width: 100%; display: block; position: relative; } ` + decodeB64("");
            shadow.appendChild(style);
            
            // 3. Inject HTML
            const container = document.createElement('div');
            container.id = 'embedded-container';
            container.className = "shadow-body " + "";
            container.setAttribute('style', "");
            container.innerHTML = decodeB64("");
            shadow.appendChild(container);

            // 4. Load Scripts
            const extJs = [];
            const loadScripts = async () => {
                for (const src of extJs) {
                    await new Promise((resolve) => {
                        const s = document.createElement('script');
                        s.src = src;
                        s.onload = resolve;
                        s.onerror = (e) => { console.error("Failed to load external script:", src, e); resolve(); };
                        shadow.appendChild(s);
                    });
                }
                
                const b64Js = "";
                if (b64Js.trim()) {
                    const jsCode = decodeB64(b64Js);
                    // Robust check for top-level import/export (not in strings/comments)
                    const isModule = /^\s*(import|export)\s+/m.test(jsCode) || jsCode.includes('import.meta');
                    
                    if (isModule) {
                        const blob = new Blob([jsCode], { type: 'text/javascript' });
                        const scriptURL = URL.createObjectURL(blob);
                        const script = document.createElement('script');
                        script.type = 'module';
                        script.src = scriptURL;
                        shadow.appendChild(script);
                    } else {
                        const script = document.createElement('script');
                        script.textContent = `
(function(shadow, userCode) {
    const docProxy = new Proxy(window.document, {
        get(target, prop) {
            if (prop === 'getElementById') return (id) => shadow.getElementById(id);
            if (prop === 'querySelector') return (sel) => shadow.querySelector(sel);
            if (prop === 'querySelectorAll') return (sel) => shadow.querySelectorAll(sel);
            if (prop === 'getElementsByClassName') return (cls) => shadow.querySelectorAll("." + cls);
            if (prop === 'getElementsByTagName') return (tag) => shadow.querySelectorAll(tag);
            const val = target[prop];
            return typeof val === 'function' ? val.bind(target) : val;
        }
    });
    try {
        const fn = new Function('document', 'shadowRoot', userCode);
        fn(docProxy, shadow);
    } catch (e) {
        console.error('Embedded Script Runtime Error:', e);
    }
})(this.shadowRoot, userCode);`;
                        shadow.appendChild(script);
                    }
                }
            };
            loadScripts();
        }
    }

    if (!customElements.get('embedded-project')) {
        customElements.define('embedded-project', EmbeddedProject);
    }
})();
